import{_ as t,o as l,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260511/F06_存貨與債務穩定度審計.md","filePath":"審計報告庫/財務審計/6261_久元/20260511/F06_存貨與債務穩定度審計.md"}'),o={name:"審計報告庫/財務審計/6261_久元/20260511/F06_存貨與債務穩定度審計.md"};function i(n,a,s,h,d,_){return l(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="f06-存貨與債務穩定度審計-財務審計專家報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務審計專家報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務審計專家報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務審計專家報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p></blockquote><h2 id="🎯-專家直斷-77-字" tabindex="-1">🎯 專家直斷（77 字） <a class="header-anchor" href="#🎯-專家直斷-77-字" aria-label="Permalink to &quot;🎯 專家直斷（77 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：流動比率 346-468%、現金 14.2 億遠超借款 0.14 億，償債無虞。存貨 2025 年去化 15%，跌價損失減半，庫存風險趨緩。</li></ul><h2 id="📊-診斷評級-128-字" tabindex="-1">📊 診斷評級（128 字） <a class="header-anchor" href="#📊-診斷評級-128-字" aria-label="Permalink to &quot;📊 診斷評級（128 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：流動比率 468%（2023）→372%→346%；速動比率 377%→272%→251%；現金 26.4 億→24.0 億→14.2 億；短期借款 0→0.50 億→0.14 億；長期借款 1.42 億→0→0；存貨 9.90 億→13.8 億（+39%）→11.7 億（-15%）；存貨週轉天數 465 天→728 天→520 天。負債率 16.8%→19.1%→18.1%。</li><li><strong>診斷見解</strong>：流動性與償債能力達 S 級水準。現金雖從 26.4 億降至 14.2 億（因 CapEx 支出），但完全覆蓋所有短期負債。存貨在 2024 年暴增 5.1 億現金流出後，2025 年成功去化約 2.1 億，跌價損失亦從 3,489 萬降至 1,716 萬（-51%），庫存風險趨緩。</li></ul><h2 id="🔍-答詢詳解-428-字" tabindex="-1">🔍 答詢詳解（428 字） <a class="header-anchor" href="#🔍-答詢詳解-428-字" aria-label="Permalink to &quot;🔍 答詢詳解（428 字）&quot;">​</a></h2><h3 id="一、存貨組成與跌價風險" tabindex="-1">一、存貨組成與跌價風險 <a class="header-anchor" href="#一、存貨組成與跌價風險" aria-label="Permalink to &quot;一、存貨組成與跌價風險&quot;">​</a></h3><ul><li><strong>核心重點</strong>：存貨由製成品 5.96 億（2024）降至 5.46 億（2025，-8%）、在製品 2.52 億降至 1.81 億（-28%）、原物料 5.25 億降至 4.38 億（-17%），三類別全面縮減。跌價損失從 3,489 萬降至 1,716 萬（-51%）。</li><li><strong>深度見解</strong>：2024 年存貨暴增 5.1 億（+39%）為經營警訊——現金流量表顯示該年存貨佔用資金 5.1 億，與應收帳款回收的 0.72 億形成強烈對比。2025 年存貨回降 2.07 億（-15%），反映管理層積極去化庫存。但存貨週轉天數仍高達 520 天，顯示營運資本效率待提升，主因代工業務所需備料週期長（設備料件交期長）。</li></ul><h3 id="二、流動性與償債能力" tabindex="-1">二、流動性與償債能力 <a class="header-anchor" href="#二、流動性與償債能力" aria-label="Permalink to &quot;二、流動性與償債能力&quot;">​</a></h3><ul><li><strong>核心重點</strong>：流動比率 346-468% 遠優於製造業 200% 標準。現金 14.2 億遠高於短期借款 0.14 億（擔保銀行借款，利率 0.70-1.29%），速動比 251%。無長期借款餘額（2024 年已清償 1.42 億）。負債率 18.1%，權益佔比 81.9%，財務結構極度穩健。</li><li><strong>深度見解</strong>：唯一流動性壓力來自現金水位持續下降——26.4 億（2023）→24.0 億（2024）→14.2 億（2025），年減 41%。主因 2025 年 CapEx 大幅擴張（購置不動產廠房設備 10.7 億），導致現金淨流出。2026 Q1 現金微升至 14.8 億，但仍較高峰期減少近半。雖短期無償債壓力，但現金消耗速度需關注。</li></ul><h3 id="三、營運週期與現金循環效率-附-2026-月營收更新" tabindex="-1">三、營運週期與現金循環效率（附 2026 月營收更新） <a class="header-anchor" href="#三、營運週期與現金循環效率-附-2026-月營收更新" aria-label="Permalink to &quot;三、營運週期與現金循環效率（附 2026 月營收更新）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：現金循環天數 423→514→484 天，始終處於 400-500 天高水位。主因存貨週轉長（465-728 天）+ DSO 逾 100 天。</li><li><strong>深度見解</strong>：設備製造需先大額備料（原物料 ~40%），從投產到收款間隔約 15 個月。2024 年 DPO 異常衝至 300 天（應付帳款大增 2.38 億），公司暫時擠壓供應商因應存貨暴增。2025 年 DSO 回歸 155 天，循環天數微降至 484 天，壓力略有緩解。<strong>2026 年 1-4 月營收累計 +6.3%（YoY），上半年動能尚可，但 4 月已轉 -1.2%，若下半年需求降溫，存貨去化速度可能再次放緩，營運週期恐再度惡化。</strong></li></ul><h2 id="💡-專家評析-284-字" tabindex="-1">💡 專家評析（284 字） <a class="header-anchor" href="#💡-專家評析-284-字" aria-label="Permalink to &quot;💡 專家評析（284 字）&quot;">​</a></h2><ol><li><strong>現金消耗速度加快（警訊）</strong>：現金從 26.4 億高點降至 14.2 億，2 年蒸發 46%，年化消耗約 6 億。若 CapEx 支出持續（2025 年 10.7 億遠超 CFO 6.6 億），現金水位將在 2-3 年內縮減至 5 億以下，屆時流動比將跌破 200% 警戒線。2026 Q1 短期借款已從 0.14 億升至 0.65 億（+364%），顯示公司已開始動用銀行額度彌補現金缺口。</li><li><strong>存貨週轉效率低於同業（風險）</strong>：520-728 天的存貨週轉天數顯著高於電子零組件同業平均（約 90-180 天）。即使考量設備業務特性，存貨週轉效率仍有相當改善空間。原物料佔比 37.5%（4.38 億/11.7 億）偏高，若半導體景氣趨緩，呆料跌價風險將顯現。</li><li><strong>負債結構極簡（正面特徵）</strong>：幾乎無銀行借款、無長期負債的架構賦予公司極大的營運彈性。但「現金充沛」的舒適區正在消退——未來擴張若全以現金支付而不善用低利率借款，可能造成股東權益報酬率（ROE）偏低。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (inventory_check 6261)</li><li>原始數據：FinMind TaiwanStockBalanceSheet, 2025 Q4 合併財報（第 8 頁資產負債表、第 36 頁存貨附註、第 48 頁借款附註）</li><li>查詢參數：stock_id=6261, start=2022-01-01, end=2026-05-11</li><li>數據查詢日期：2026-05-11</li></ul>',19)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
